    // ── Stats ──────────────────────────────────────────────────────────
    @GetMapping("/stats")
    public ResponseEntity<Map<String, Object>> getStats() {
        Map<String, Object> stats = new HashMap<>();
        
        List<com.eventbooking.model.Event> allEvents = eventRepository.findAll();
        List<com.eventbooking.model.Booking> allBookings = bookingRepository.findAll();
        List<User> allUsers = userRepository.findAll();
        
        long totalEvents = allEvents.size();
        long totalBookings = allBookings.size();
        long totalUsers = allUsers.size();
        
        long studentAccounts = allUsers.stream().filter(u -> u.getRole() == User.Role.STUDENT).count();
        long facultyAccounts = allUsers.stream().filter(u -> u.getRole() == User.Role.FACULTY).count();
        long pendingFaculty = allUsers.stream().filter(u -> u.getRole() == User.Role.FACULTY && !u.isApproved()).count();
        
        long teamRegistrations = allBookings.stream().filter(b -> Boolean.TRUE.equals(b.isTeamBooking())).count();
        long individualRegistrations = totalBookings - teamRegistrations;
        long accommodationBookings = allBookings.stream().filter(b -> Boolean.TRUE.equals(b.isAccommodationRequired())).count();
        
        long upcomingEvents = allEvents.stream().filter(e -> e.getStatus() == com.eventbooking.model.Event.EventStatus.PUBLISHED || e.getStatus() == com.eventbooking.model.Event.EventStatus.REGISTRATION_OPEN).count();
        long completedEvents = allEvents.stream().filter(e -> e.getStatus() == com.eventbooking.model.Event.EventStatus.COMPLETED).count();

        stats.put("totalEvents", totalEvents);
        stats.put("totalBookings", totalBookings);
        stats.put("totalUsers", totalUsers);
        stats.put("totalRevenue", bookingRepository.getTotalRevenue() != null ? bookingRepository.getTotalRevenue() : BigDecimal.ZERO);
        stats.put("totalTicketsSold", bookingRepository.getTotalTicketsSold() != null ? bookingRepository.getTotalTicketsSold() : 0L);
        stats.put("pendingFaculty", pendingFaculty);
        
        stats.put("studentAccounts", studentAccounts);
        stats.put("facultyAccounts", facultyAccounts);
        stats.put("teamRegistrations", teamRegistrations);
        stats.put("individualRegistrations", individualRegistrations);
        stats.put("accommodationBookings", accommodationBookings);
        stats.put("upcomingEvents", upcomingEvents);
        stats.put("completedEvents", completedEvents);
        
        return ResponseEntity.ok(stats);
    }

