    // ── Send Announcement ────────────────────────────────────────────
    @PostMapping("/announcements")
    public ResponseEntity<Map<String, Object>> sendAnnouncement(@RequestBody AnnouncementRequest req) {
        // Get eligible users based on optional filters
        List<User> users = new java.util.ArrayList<>(userRepository.findEligibleStudents(
            req.getTargetDepartment() != null && !req.getTargetDepartment().isEmpty() ? List.of(req.getTargetDepartment()) : null, 
            req.getTargetYear() != null ? List.of(req.getTargetYear()) : null
        ));
        // Also include approved faculty
        List<User> faculty = userRepository.findByRoleAndApproved(User.Role.FACULTY, true);
        users.addAll(faculty);

        // Include all registered attendees across all events to ensure team members get announcements
        List<Attendee> allAttendees = attendeeRepository.findAll();
        for (Attendee a : allAttendees) {
            if (a.getEmail() != null && !a.getEmail().isBlank()) {
                User dummy = new User();
                dummy.setName(a.getName() != null ? a.getName() : "Student");
                dummy.setEmail(a.getEmail());
                dummy.setRole(User.Role.STUDENT);
                users.add(dummy);
            }
        }

        // Remove duplicates by email
        List<User> unique = new java.util.ArrayList<>();
        java.util.Set<String> seenEmails = new java.util.HashSet<>();
        for (User u : users) {
            if (u.getEmail() != null && seenEmails.add(u.getEmail())) {
                unique.add(u);
            }
        }

        emailService.sendAnnouncementEmails(unique, req.getSubject(), req.getMessage());
        return ResponseEntity.ok(Map.of("message", "Announcement queued for " + unique.size() + " recipients.", "recipientCount", unique.size()));
    }

